w("src/services/socket.js", dedent("""
// ARCHITECTURE NOTE: Layered ws://localhost:8080/ws ; Event-Driven ws://localhost:8083/ws
import { io } from 'socket.io-client'
const WS_URL = import.meta.env.VITE_WS_URL || 'http://localhost:8080'
class SocketService {
  constructor(){ this.socket = null }
  connect(token){ this.socket = io(WS_URL,{ auth:{token}, transports:['websocket'] }); return this.socket }
  joinDocument(documentId,userId){ this.socket?.emit('join-document',{documentId,userId}) }
  leaveDocument(documentId){ this.socket?.emit('leave-document',{documentId}) }
  sendEdit(documentId,content,userId){ this.socket?.emit('document-edit',{documentId,content,userId}) }
  onDocumentUpdate(cb){ this.socket?.on('document-update',cb) }
  onUserJoined(cb){ this.socket?.on('user-joined',cb) }
  onUserLeft(cb){ this.socket?.on('user-left',cb) }
  onNotification(cb){ this.socket?.on('notification',cb) }
  disconnect(){ this.socket?.disconnect() }
}
export default new SocketService()
"""))

w("src/contexts/AuthContext.jsx", "import { createContext,useContext,useMemo,useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { logout as apiLogout } from '../services/api'\nconst AuthContext=createContext(null)\nexport function AuthProvider({children}){const [token,setToken]=useState(localStorage.getItem('cn_token')); const [user,setUser]=useState(JSON.parse(localStorage.getItem('cn_user')||'null')); const navigate=useNavigate(); const login=(t,u)=>{localStorage.setItem('cn_token',t);localStorage.setItem('cn_user',JSON.stringify(u));setToken(t);setUser(u)}; const logout=async()=>{try{await apiLogout()}catch{} localStorage.removeItem('cn_token');localStorage.removeItem('cn_user');setToken(null);setUser(null);navigate('/login')}; const value=useMemo(()=>({user,token,login,logout}),[user,token]); return <AuthContext.Provider value={value}>{children}</AuthContext.Provider> }\nexport const useAuth=()=>useContext(AuthContext)")
w("src/contexts/ToastContext.jsx", "import { createContext,useContext,useMemo,useState } from 'react'\nconst ToastContext=createContext(null)\nexport function ToastProvider({children}){const [items,setItems]=useState([]); const push=(type,message)=>{const id=Date.now()+Math.random(); setItems((p)=>[...p,{id,type,message}]); setTimeout(()=>setItems((p)=>p.filter((x)=>x.id!==id)),3000)}; const toast=useMemo(()=>({success:(m)=>push('success',m),error:(m)=>push('error',m),info:(m)=>push('info',m)}),[]); return <ToastContext.Provider value={{items,toast}}>{children}</ToastContext.Provider>}\nexport const useToast=()=>useContext(ToastContext)")

