w("src/components/CreateDocumentModal.jsx", header.format(path="src/components/CreateDocumentModal.jsx")+"import { useState } from 'react'\nimport { createDocument } from '../services/api'\nexport default function CreateDocumentModal({isOpen,onClose,onCreated}){const [title,setTitle]=useState(''); const [content,setContent]=useState(''); const [visibility,setVisibility]=useState('private'); const [ok,setOk]=useState(false); if(!isOpen) return null; const submit=async()=>{if(!title.trim())return; await createDocument(title,content,visibility); onCreated?.(); setOk(true); setTimeout(()=>{setOk(false); onClose?.()},1500)}; return <div className='fixed inset-0 z-50 flex items-center justify-center bg-black/40'><div className='w-full max-w-lg rounded-modal bg-white p-6'><div className='mb-4 flex items-center justify-between'><h3 className='text-xl font-bold'>Create New Document</h3><span className='rounded-full bg-editor-bg px-3 py-1 text-xs text-editor-text'>Unique Doc ID auto-assigned on creation</span></div><label className='text-[13px] font-medium'>Document Title</label><input className='mt-1 h-10 w-full rounded-button border border-border px-3' placeholder='Enter a title...' value={title} onChange={(e)=>setTitle(e.target.value)}/><label className='mt-3 block text-[13px] font-medium'>Initial Content (optional)</label><textarea rows={4} className='mt-1 w-full rounded-button border border-border p-3' value={content} onChange={(e)=>setContent(e.target.value)}/><label className='mt-3 block text-[13px] font-medium'>Visibility</label><div className='mt-1 flex gap-4 text-sm'><label><input type='radio' checked={visibility==='private'} onChange={()=>setVisibility('private')}/> Private (only me)</label><label><input type='radio' checked={visibility==='shared'} onChange={()=>setVisibility('shared')}/> Shared (invite others)</label></div><div className='mt-5 flex justify-end gap-2'>{ok?<div className='text-sm font-medium text-success'>✓ Document created successfully</div>:<><button className='h-10 rounded-button border border-border px-4' onClick={onClose}>Cancel</button><button className='h-10 rounded-button bg-primary px-4 text-white' onClick={submit}>Create Document</button></>}</div></div></div> }")
w("src/components/ShareDocumentModal.jsx", header.format(path="src/components/ShareDocumentModal.jsx")+"import { useEffect,useMemo,useState } from 'react'\nimport { searchUsers,shareDocument } from '../services/api'\nimport Avatar from './Avatar'\nimport Badge from './Badge'\nexport default function ShareDocumentModal({documentId,documentTitle,collaborators=[],isOpen,onClose}){const [query,setQuery]=useState(''); const [results,setResults]=useState([]); const [pending,setPending]=useState([]); const [linkSharing,setLinkSharing]=useState('disabled'); useEffect(()=>{if(!query.trim()){setResults([]);return} const t=setTimeout(async()=>{const r=await searchUsers(query); setResults(r.data||[])},300); return ()=>clearTimeout(t)},[query]); if(!isOpen) return null; const list=useMemo(()=>[...collaborators,...pending],[collaborators,pending]); const send=async()=>{await shareDocument(documentId,{invitees:pending.map((u)=>({userId:u.id,role:'editor'})),linkSharing}); onClose?.()}; return <div className='fixed inset-0 z-50 flex items-center justify-center bg-black/40'><div className='w-full max-w-xl rounded-modal bg-white p-6'><h3 className='text-xl font-bold'>Share — '{documentTitle}'</h3><p className='mt-2 inline-block rounded-full bg-editor-bg px-3 py-1 text-xs text-editor-text'>Only registered users can be invited</p><label className='mt-4 block text-[13px] font-medium'>Invite by username or email</label><input className='mt-1 h-10 w-full rounded-button border border-border px-3' value={query} onChange={(e)=>setQuery(e.target.value)}/>{results.length>0?<div className='mt-1 max-h-36 overflow-y-auto rounded-button border border-border'>{results.map((u)=><button key={u.id} className='flex w-full items-center gap-2 px-3 py-2 hover:bg-background' onClick={()=>setPending((p)=>p.some((x)=>x.id===u.id)?p:[...p,u])}><Avatar name={u.username}/><span>{u.username}</span></button>)}</div>:null}<h4 className='mt-4 text-sm font-semibold'>Current Collaborators</h4><div className='mt-2 space-y-2'>{list.map((c,i)=><div key={`${c.id}-${i}`} className='flex items-center justify-between rounded-button border border-border p-2'><div className='flex items-center gap-2'><Avatar name={c.username||c.name}/><span className='text-sm'>{c.username||c.name}</span></div><Badge type={i===0?'owner':'editor'}/></div>)}</div><h4 className='mt-4 text-sm font-semibold'>Link Sharing</h4><div className='mt-2 grid grid-cols-3 gap-2'>{['disabled','view only','can edit'].map((v)=><button key={v} className={`h-9 rounded-button border text-sm ${linkSharing===v?'border-primary bg-primary text-white':'border-border'}`} onClick={()=>setLinkSharing(v)}>{v}</button>)}</div><button className='mt-5 h-[42px] w-full rounded-button bg-primary text-white' onClick={send}>Send Invitations</button></div></div> }")
