w("src/pages/LoginPage.jsx", header.format(path="src/pages/LoginPage.jsx")+"import { useMemo,useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { login as apiLogin,register as apiRegister } from '../services/api'\nimport { useAuth } from '../contexts/AuthContext'\nexport default function LoginPage(){const [tab,setTab]=useState('login'); const [username,setUsername]=useState(''); const [email,setEmail]=useState(''); const [password,setPassword]=useState(''); const [confirmPassword,setConfirmPassword]=useState(''); const [error,setError]=useState(null); const [loading,setLoading]=useState(false); const navigate=useNavigate(); const auth=useAuth(); const strength=useMemo(()=>{if(password.length<8)return{w:'25%',c:'bg-danger',l:''}; const n=/\\d/.test(password), s=/[^A-Za-z0-9]/.test(password); if(!n)return{w:'50%',c:'bg-warning',l:''}; if(!s)return{w:'75%',c:'bg-warning',l:''}; return{w:'100%',c:'bg-success',l:'Strong password'}},[password]); const submit=async(e)=>{e.preventDefault(); setLoading(true); setError(null); try{if(tab==='login'){const r=await apiLogin(username,password); auth.login(r.data.token,r.data.user)} else {if(password!==confirmPassword) throw new Error('Passwords do not match'); const r=await apiRegister(username,email,password); auth.login(r.data.token,r.data.user)} navigate('/dashboard')}catch(err){setError(err?.response?.status===401?'Invalid username or password. Please try again.':err.message)}finally{setLoading(false)}}; return <div className='flex min-h-screen items-center justify-center bg-background p-4'><form onSubmit={submit} className='w-full max-w-[400px] rounded-card border border-border bg-white p-6'><div className='mb-4 flex border-b border-border text-sm font-medium'><button type='button' className={`pb-2 ${tab==='login'?'border-b-2 border-primary text-primary':'text-text-secondary'}`} onClick={()=>setTab('login')}>Login</button><button type='button' className={`ml-4 pb-2 ${tab==='register'?'border-b-2 border-primary text-primary':'text-text-secondary'}`} onClick={()=>setTab('register')}>Register</button></div><h1 className='text-2xl font-bold'>{tab==='login'?'Welcome back':'Create an account'}</h1>{tab==='login'?<p className='mt-1 text-sm text-text-secondary'>Sign in to access your documents</p>:null}{error?<div className='mt-4 rounded-button border-l-4 border-warning bg-amber-50 p-3 text-sm text-amber-800'>⚠ {error}</div>:null}<label className='mt-4 block text-[13px] font-medium'>Username</label><input className='mt-1 h-10 w-full rounded-button border border-border px-3' placeholder='Enter your username' value={username} onChange={(e)=>setUsername(e.target.value)}/>{tab==='register'?<><label className='mt-3 block text-[13px] font-medium'>Email</label><input className='mt-1 h-10 w-full rounded-button border border-border px-3' value={email} onChange={(e)=>setEmail(e.target.value)}/></>:null}<label className='mt-3 block text-[13px] font-medium'>Password</label><input type='password' className='mt-1 h-10 w-full rounded-button border border-border px-3' placeholder='••••••••' value={password} onChange={(e)=>setPassword(e.target.value)}/>{tab==='register'?<><div className='mt-2 h-2 w-full rounded-full bg-gray-100'><div className={`h-2 rounded-full ${strength.c}`} style={{width:strength.w}}/></div>{strength.l?<p className='mt-1 text-xs text-success'>{strength.l}</p>:null}<label className='mt-3 block text-[13px] font-medium'>Confirm Password</label><input type='password' className={`mt-1 h-10 w-full rounded-button border px-3 ${confirmPassword&&confirmPassword!==password?'border-danger':'border-border'}`} value={confirmPassword} onChange={(e)=>setConfirmPassword(e.target.value)}/>{confirmPassword&&confirmPassword!==password?<p className='mt-1 text-xs text-danger'>Passwords do not match</p>:null}</>:null}<button disabled={loading} className='mt-5 h-[42px] w-full rounded-button bg-primary font-semibold text-white hover:bg-primary-hover'>{tab==='login'?'Sign In':'Create Account'}</button>{tab==='login'?<div className='mt-3 flex justify-between text-[13px]'><a className='text-primary' href='#'>Forgot password?</a><button type='button' className='text-primary' onClick={()=>setTab('register')}>Create an account</button></div>:null}</form></div> }")
w("src/pages/DashboardPage.jsx", "export { default } from './DashboardPageImpl.jsx'")
w("src/pages/DashboardPageImpl.jsx", header.format(path="src/pages/DashboardPage.jsx")+"import { useEffect,useMemo,useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { getDocuments,getNotifications,deleteDocument } from '../services/api'\nimport { useAuth } from '../contexts/AuthContext'\nimport Navbar from '../components/Navbar'\nimport Avatar from '../components/Avatar'\nimport Badge from '../components/Badge'\nimport CreateDocumentModal from '../components/CreateDocumentModal'\nimport ConfirmDialog from '../components/ConfirmDialog'\nconst rel=(iso)=>{const m=Math.floor((Date.now()-new Date(iso).getTime())/60000); if(m<60)return`${m} min ago`; if(m<1440)return`${Math.floor(m/60)} hr ago`; return'Yesterday'}\nexport default function DashboardPage(){const [documents,setDocuments]=useState([]); const [filter,setFilter]=useState('all'); const [sort,setSort]=useState('date'); const [notifications,setNotifications]=useState([]); const [showNew,setShowNew]=useState(false); const [toDelete,setToDelete]=useState(null); const {user,logout}=useAuth(); const navigate=useNavigate(); const load=async()=>{const [d,n]=await Promise.all([getDocuments(),getNotifications()]); setDocuments(d.data||[]); setNotifications((n.data||[]).slice(0,3))}; useEffect(()=>{load()},[]); const view=useMemo(()=>{let l=[...documents]; if(filter==='mine')l=l.filter((d)=>d.ownerId===user?.id); if(filter==='shared')l=l.filter((d)=>d.ownerId!==user?.id); if(sort==='date')l.sort((a,b)=>new Date(b.updatedAt)-new Date(a.updatedAt)); if(sort==='nameaz')l.sort((a,b)=>a.title.localeCompare(b.title)); if(sort==='nameza')l.sort((a,b)=>b.title.localeCompare(a.title)); return l},[documents,filter,sort,user]); const remove=async()=>{if(!toDelete)return; await deleteDocument(toDelete.id); setToDelete(null); load()}; return <div><Navbar currentPage='dashboard' username={user?.username} onLogout={logout} notifCount={notifications.filter((n)=>!n.read).length}/><div className='mx-auto flex max-w-app'><aside className='w-sidebar border-r border-border bg-white p-4'><p className='text-xs font-semibold text-text-secondary'>FILTER</p><div className='mt-2 space-y-1'>{[{k:'all',l:'All Documents'},{k:'mine',l:'My Documents'},{k:'shared',l:'Shared With Me'}].map((f)=><button key={f.k} className={`block w-full rounded-button px-3 py-2 text-left text-sm ${filter===f.k?'bg-primary text-white':'hover:bg-background'}`} onClick={()=>setFilter(f.k)}>{f.l}</button>)}</div><p className='mt-6 text-xs font-semibold text-text-secondary'>SORT BY</p><div className='mt-2 space-y-2 text-sm'>{[{k:'date',l:'Date Modified'},{k:'nameaz',l:'Name A→Z'},{k:'nameza',l:'Name Z→A'}].map((s)=><label key={s.k} className='block'><input type='radio' className='mr-2' checked={sort===s.k} onChange={()=>setSort(s.k)}/>{s.l}</label>)}</div><div className='mt-6 rounded-button border-l-4 border-warning bg-amber-50 p-3'><p className='text-sm font-semibold'>Notifications ({notifications.filter((n)=>!n.read).length})</p><ul className='mt-2 list-disc pl-4 text-[13px] text-text-secondary'>{notifications.map((n)=><li key={n.id}>{n.actor} {n.type} {n.documentTitle}</li>)}</ul><button className='mt-2 text-sm text-primary' onClick={()=>navigate('/notifications')}>View all →</button></div></aside><main className='flex-1 p-6'><div className='mb-4 flex items-start justify-between'><div><h1 className='text-2xl font-bold'>My Documents</h1><p className='text-[13px] text-text-secondary'>{view.length} documents · last updated {view[0]?rel(view[0].updatedAt):'n/a'}</p></div><button className='h-[38px] rounded-button bg-primary px-4 text-sm font-semibold text-white' onClick={()=>setShowNew(true)}>+ New Document</button></div><div className='grid grid-cols-[repeat(auto-fill,minmax(220px,1fr))] gap-4'><button className='flex min-h-[170px] flex-col items-center justify-center rounded-card border-2 border-dashed border-border bg-white text-text-secondary' onClick={()=>setShowNew(true)}><span className='text-2xl'>+</span><span className='text-sm'>New Document</span></button>{view.map((doc)=><article key={doc.id} className='rounded-card border border-border bg-white p-3'><h3 className='truncate text-base font-semibold'>{doc.title}</h3><p className='mt-1 text-[13px] text-text-secondary'>Owner: {doc.ownerName}</p><div className='mt-2 flex -space-x-2'>{(doc.collaborators||[]).slice(0,3).map((c)=><Avatar key={c.id} name={c.username}/>)}</div><p className='mt-2 text-xs text-muted'>Modified {rel(doc.updatedAt)}</p><div className='mt-3 flex items-center justify-between'><Badge type={doc.ownerId===user?.id?'owner':'shared'}/><div className='flex gap-1'><button className='h-7 rounded-button border border-border px-2 text-xs' onClick={()=>navigate(`/documents/${doc.id}`)}>Open</button>{doc.ownerId===user?.id?<button className='h-7 rounded-button border border-danger px-2 text-xs text-danger' onClick={()=>setToDelete(doc)}>Del</button>:null}</div></div></article>)}</div></main></div><CreateDocumentModal isOpen={showNew} onClose={()=>setShowNew(false)} onCreated={load}/><ConfirmDialog isOpen={!!toDelete} title='Delete document' message={`Delete '${toDelete?.title||''}'?`} confirmLabel='Delete' danger onCancel={()=>setToDelete(null)} onConfirm={remove}/></div> }")
w("src/pages/EditorPage.jsx", header.format(path="src/pages/EditorPage.jsx")+"import { useEffect,useMemo,useRef,useState } from 'react'\nimport { useNavigate,useParams } from 'react-router-dom'\nimport Navbar from '../components/Navbar'\nimport Avatar from '../components/Avatar'\nimport ShareDocumentModal from '../components/ShareDocumentModal'\nimport { getDocument,saveDocument } from '../services/api'\nimport { useAuth } from '../contexts/AuthContext'\nimport { useToast } from '../contexts/ToastContext'\nimport socketService from '../services/socket'\nexport default function EditorPage(){const {id}=useParams(); const {user,token,logout}=useAuth(); const {toast}=useToast(); const navigate=useNavigate(); const [doc,setDoc]=useState(null); const [content,setContent]=useState(''); const [activeUsers,setActiveUsers]=useState([]); const [lastSaved,setLastSaved]=useState(null); const [saving,setSaving]=useState(false); const [showShare,setShowShare]=useState(false); const timerRef=useRef(null); useEffect(()=>{(async()=>{const r=await getDocument(id); setDoc(r.data); setContent(r.data?.content||'')})()},[id]); useEffect(()=>{socketService.connect(token); socketService.joinDocument(id,user?.id); socketService.onDocumentUpdate((p)=>setContent(p.content||'')); socketService.onUserJoined((u)=>setActiveUsers((a)=>a.some((x)=>x.userId===u.userId)?a:[...a,u])); socketService.onUserLeft((u)=>setActiveUsers((a)=>a.filter((x)=>x.userId!==u.userId))); return ()=>{socketService.leaveDocument(id); socketService.disconnect()}},[id,token,user]); useEffect(()=>{clearTimeout(timerRef.current); timerRef.current=setTimeout(async()=>{if(!doc)return; setSaving(true); await saveDocument(id,content); setLastSaved(new Date()); setSaving(false)},3000); return ()=>clearTimeout(timerRef.current)},[content,id,doc]); const c=useMemo(()=>({w:content.trim()?content.trim().split(/\\s+/).length:0,ch:content.length}),[content]); const saveNow=async()=>{setSaving(true); await saveDocument(id,content); socketService.sendEdit(id,content,user?.id); setLastSaved(new Date()); setSaving(false); toast.success('Document saved!')}; return <div><Navbar currentPage='documents' username={user?.username} onLogout={logout}/><div className='border-b border-border bg-white'><div className='mx-auto flex h-navbar max-w-app items-center justify-between px-4'><div className='text-lg font-semibold'>📝 {doc?.title||'Untitled'}</div><div className='rounded-full bg-green-100 px-3 py-1 text-xs text-green-700'>● Active text editing over</div><div className='flex items-center gap-2'><span className='text-xs text-muted'>Last saved: {lastSaved?`${Math.max(1,Math.floor((Date.now()-lastSaved.getTime())/60000))} min ago`:'never'}</span><button className='h-9 rounded-button border border-border px-3 text-sm' onClick={()=>setShowShare(true)}>Share</button><button className='h-9 rounded-button border border-border px-3 text-sm' onClick={()=>navigate(`/documents/${id}/history`)}>History</button><button className='h-9 rounded-button bg-primary px-3 text-sm text-white' onClick={saveNow}>{saving?'Saving...':'Save'}</button></div></div></div><div className='mx-auto flex max-w-app'><section className='relative flex-1 p-4'><div contentEditable suppressContentEditableWarning className='min-h-[calc(100vh-160px)] rounded-card border border-border bg-white p-4 outline-none' onInput={(e)=>setContent(e.currentTarget.textContent||'')}>{content}</div><div className='absolute bottom-6 left-8 text-xs text-text-secondary'>Blue = your edit · Green = collaborator edit</div><div className='absolute bottom-6 right-8 text-xs text-text-secondary'>Words: {c.w} · Characters: {c.ch}</div></section><aside className='w-[220px] border-l border-border bg-white p-4'><h3 className='text-sm font-semibold'>Active Users</h3><div className='mt-3 space-y-2'><div className='flex items-center gap-2'><Avatar name={user?.username} color='blue'/><span className='text-sm'>You ({user?.username})</span><span className='ml-auto text-green-500'>●</span></div>{activeUsers.length===0?<p className='text-sm text-muted'>Only you are active</p>:activeUsers.map((u)=><div key={u.userId} className='flex items-center gap-2'><Avatar name={u.username} color='green'/><span className='text-sm'>{u.username}</span><span className='ml-auto text-green-500'>●</span></div>)}</div></aside></div><ShareDocumentModal documentId={id} documentTitle={doc?.title||''} collaborators={doc?.collaborators||[]} isOpen={showShare} onClose={()=>setShowShare(false)}/></div> }")
w("src/pages/VersionHistoryPage.jsx", header.format(path="src/pages/VersionHistoryPage.jsx")+"import { useEffect,useMemo,useState } from 'react'\nimport { useNavigate,useParams } from 'react-router-dom'\nimport Navbar from '../components/Navbar'\nimport RestoreVersionModal from '../components/RestoreVersionModal'\nimport { getDocument,getRevisions } from '../services/api'\nimport { useAuth } from '../contexts/AuthContext'\nexport default function VersionHistoryPage(){const {id}=useParams(); const {user,logout}=useAuth(); const [documentTitle,setDocumentTitle]=useState(''); const [revisions,setRevisions]=useState([]); const [chrono,setChrono]=useState(false); const [selected,setSelected]=useState(null); const navigate=useNavigate(); const load=async()=>{const [d,r]=await Promise.all([getDocument(id),getRevisions(id)]); setDocumentTitle(d.data?.title||''); setRevisions(r.data||[])}; useEffect(()=>{load()},[id]); const list=useMemo(()=>chrono?[...revisions].reverse():revisions,[revisions,chrono]); return <div><Navbar currentPage='documents' username={user?.username} onLogout={logout}/><div className='mx-auto max-w-app p-6'><div className='mb-6 flex items-center justify-between'><h1 className='text-2xl font-bold'>Version History — '{documentTitle}'</h1><button className='rounded-full border border-border px-3 py-1 text-sm' onClick={()=>setChrono((c)=>!c)}>{chrono?'Newest first':'Chronological · newest first'}</button></div><div className='space-y-4'>{list.map((r,idx)=><div key={r.id} className='flex gap-3'><div className='flex w-6 flex-col items-center'><div className={`h-3 w-3 rounded-full ${r.current?'bg-primary':'bg-border'}`}/>{idx!==list.length-1?<div className='mt-1 h-full w-px bg-border'/>:null}</div><div className='flex-1 rounded-card border border-border bg-white p-4'><div className='flex items-center justify-between'><div className='text-sm font-semibold'>v{r.version} {r.current?'(Current)':''}</div>{r.current?<span className='rounded-full bg-green-100 px-2 py-0.5 text-xs text-green-700'>Current</span>:<button className='rounded-button border border-border px-3 py-1 text-sm' onClick={()=>setSelected(r)}>Restore</button>}</div><p className='mt-1 text-[13px] text-text-secondary'>{r.username} · {new Date(r.createdAt).toLocaleString()}</p><p className='mt-2 text-sm'>{r.change}</p></div></div>)}</div><button className='mt-5 text-sm text-primary' onClick={()=>navigate(`/documents/${id}`)}>← Back to editor</button></div><RestoreVersionModal isOpen={!!selected} onClose={()=>setSelected(null)} documentId={id} documentTitle={documentTitle} selectedVersion={selected} currentVersion={revisions.find((x)=>x.current)} onRestored={()=>navigate(`/documents/${id}`)}/></div> }")
w("src/pages/NotificationsPage.jsx", header.format(path="src/pages/NotificationsPage.jsx")+"import { useEffect,useMemo,useState } from 'react'\nimport { BellIcon,PencilSquareIcon,ArrowPathIcon,UserGroupIcon } from '@heroicons/react/24/outline'\nimport Navbar from '../components/Navbar'\nimport { getNotifications,markAllRead } from '../services/api'\nimport socketService from '../services/socket'\nimport { useAuth } from '../contexts/AuthContext'\nexport default function NotificationsPage(){const {user,token,logout}=useAuth(); const [notifications,setNotifications]=useState([]); const [filter,setFilter]=useState('all'); const [loading,setLoading]=useState(true); useEffect(()=>{(async()=>{const r=await getNotifications(); setNotifications(r.data||[]); setLoading(false)})()},[]); useEffect(()=>{socketService.connect(token); socketService.onNotification((n)=>setNotifications((p)=>[n,...p])); return ()=>socketService.disconnect()},[token]); const shown=useMemo(()=>filter==='all'?notifications:notifications.filter((n)=>n.type===filter.slice(0,-1)),[notifications,filter]); const icon=(t)=>t==='share'?<UserGroupIcon className='h-4 w-4'/>:t==='edit'?<PencilSquareIcon className='h-4 w-4'/>:<ArrowPathIcon className='h-4 w-4'/>; const bg=(t)=>t==='share'?'bg-owner-bg text-owner-text':t==='edit'?'bg-shared-bg text-shared-text':'bg-editor-bg text-editor-text'; return <div><Navbar currentPage='notifications' username={user?.username} onLogout={logout} notifCount={notifications.filter((n)=>!n.read).length}/><div className='mx-auto max-w-app p-6'><div className='mb-4 flex items-center justify-between'><h1 className='text-2xl font-bold'>Notifications</h1><button className='h-9 rounded-button border border-border px-3 text-sm' onClick={async()=>{await markAllRead(); setNotifications((p)=>p.map((n)=>({...n,read:true})))}}>Mark all as read</button></div><div className='mb-3 flex border-b border-border'>{['all','shares','edits','restores'].map((t)=><button key={t} className={`-mb-px mr-4 border-b-2 pb-2 text-sm font-medium ${filter===t?'border-primary text-primary':'border-transparent text-text-secondary'}`} onClick={()=>setFilter(t)}>{t[0].toUpperCase()+t.slice(1)}</button>)}</div>{loading?<div className='py-10 text-center text-text-secondary'><BellIcon className='mx-auto h-6 w-6'/> Loading...</div>:<div>{shown.map((n)=><div key={n.id} className='flex min-h-12 items-center justify-between border-b border-border px-1 py-3 hover:bg-background'><div className='flex items-center gap-3'><div className={`flex h-7 w-7 items-center justify-center rounded-full ${bg(n.type)}`}>{icon(n.type)}</div><div><p className='text-sm'>{n.actor} {n.type==='share'?'shared':n.type==='edit'?'edited':'restored'} {n.documentTitle}</p><p className='text-xs text-muted'>{n.relativeTime||'just now'}</p></div></div>{!n.read?<span className='h-2 w-2 rounded-full bg-primary'/>:null}</div>)}</div>}</div></div> }")
w("src/App.jsx", header.format(path="src/App.jsx")+"import { BrowserRouter,Navigate,Route,Routes,useLocation } from 'react-router-dom'\nimport { AuthProvider } from './contexts/AuthContext'\nimport { ToastProvider } from './contexts/ToastContext'\nimport Toast from './components/Toast'\nimport LoginPage from './pages/LoginPage'\nimport DashboardPage from './pages/DashboardPage'\nimport EditorPage from './pages/EditorPage'\nimport VersionHistoryPage from './pages/VersionHistoryPage'\nimport NotificationsPage from './pages/NotificationsPage'\nfunction PrivateRoute({children}){const t=localStorage.getItem('cn_token'); const location=useLocation(); if(!t) return <Navigate to='/login' state={{from:location}} replace/>; return children}\nfunction AppRoutes(){return <Routes><Route path='/login' element={<LoginPage/>}/><Route path='/dashboard' element={<PrivateRoute><DashboardPage/></PrivateRoute>}/><Route path='/documents/new' element={<PrivateRoute><DashboardPage/></PrivateRoute>}/><Route path='/documents/:id' element={<PrivateRoute><EditorPage/></PrivateRoute>}/><Route path='/documents/:id/history' element={<PrivateRoute><VersionHistoryPage/></PrivateRoute>}/><Route path='/notifications' element={<PrivateRoute><NotificationsPage/></PrivateRoute>}/><Route path='/' element={<Navigate to='/dashboard' replace/>}/></Routes>}\nexport default function App(){return <BrowserRouter><AuthProvider><ToastProvider><AppRoutes/><Toast/></ToastProvider></AuthProvider></BrowserRouter> }")
w("src/main.jsx", "import React from 'react'\nimport ReactDOM from 'react-dom/client'\nimport App from './App'\nimport './index.css'\nReactDOM.createRoot(document.getElementById('root')).render(<React.StrictMode><App/></React.StrictMode>)")

